import {
	useCurrentFrame,
	useVideoConfig,
	interpolate,
	Easing,
	Sequence,
	staticFile,
	AbsoluteFill,
} from 'remotion';
import { Audio } from '@remotion/media';

const SCENE1_FRAMES = 412;
const SCENE2_FRAMES = 543;
const SCENE3_FRAMES = 520;
const SCENE4_FRAMES = 514;
const SCENE5_FRAMES = 454;
const SCENE6_FRAMES = 482;
const SCENE7_FRAMES = 286;

const FADE_FRAMES = 18;

const fadeInOut = (frame: number, durationInFrames: number, fadeFrames: number) => {
	const fadeIn = interpolate(frame, [0, fadeFrames], [0, 1], {
		extrapolateLeft: 'clamp',
		extrapolateRight: 'clamp',
		easing: Easing.bezier(0.16, 1, 0.3, 1),
	});
	const fadeOut = interpolate(
		frame,
		[durationInFrames - fadeFrames, durationInFrames],
		[1, 0],
		{
			extrapolateLeft: 'clamp',
			extrapolateRight: 'clamp',
			easing: Easing.bezier(0.45, 0, 0.55, 1),
		},
	);
	return fadeIn * fadeOut;
};

const animateIn = (frame: number, delay: number, fps: number) => {
	const startFrame = delay * fps;
	return {
		opacity: interpolate(frame, [startFrame, startFrame + 15], [0, 1], {
			extrapolateLeft: 'clamp',
			extrapolateRight: 'clamp',
			easing: Easing.bezier(0.16, 1, 0.3, 1),
		}),
		translateY: interpolate(frame, [startFrame, startFrame + 15], [30, 0], {
			extrapolateLeft: 'clamp',
			extrapolateRight: 'clamp',
			easing: Easing.bezier(0.16, 1, 0.3, 1),
		}),
	};
};

/* ── Scene 1: The Problem ────────────────────────────── */
const Scene1: React.FC = () => {
	const frame = useCurrentFrame();
	const { fps, durationInFrames } = useVideoConfig();
	const opacity = fadeInOut(frame, durationInFrames, FADE_FRAMES);
	const title = animateIn(frame, 0, fps);
	const sub = animateIn(frame, 0.4, fps);
	const code = animateIn(frame, 0.8, fps);

	return (
		<AbsoluteFill
			style={{ opacity, backgroundColor: '#0f172a' }}
			className="flex flex-col items-center justify-center px-20"
		>
			<div
				style={{
					opacity: title.opacity,
					transform: `translateY(${title.translateY}px)`,
				}}
				className="text-6xl font-bold text-white mb-6 text-center"
			>
				Web Scraping with AI?
			</div>
			<div
				style={{
					opacity: sub.opacity,
					transform: `translateY(${sub.translateY}px)`,
				}}
				className="text-3xl text-slate-400 mb-10 text-center"
			>
				The DOM is a nightmare for LLMs
			</div>
			<div
				style={{
					opacity: code.opacity,
					transform: `translateY(${code.translateY}px)`,
				}}
				className="bg-slate-800 rounded-xl px-10 py-6 font-mono text-xl text-red-400"
			>
				{'<div class="xyz_3k9"> <span> <div> ...'}
			</div>
		</AbsoluteFill>
	);
};

/* ── Scene 2: Meet fastbrowser ───────────────────────── */
const Scene2: React.FC = () => {
	const frame = useCurrentFrame();
	const { fps, durationInFrames } = useVideoConfig();
	const opacity = fadeInOut(frame, durationInFrames, FADE_FRAMES);
	const title = animateIn(frame, 0, fps);
	const cmds = [
		{ text: '$ fastbrowser navigate_page --url https://example.com', delay: 0.5 },
		{ text: '$ fastbrowser take_snapshot', delay: 1.0 },
		{ text: '$ fastbrowser click -s \'button[name="Login"]\'', delay: 1.5 },
		{ text: '$ fastbrowser fill_form -s \'searchbox\' --value "hello"', delay: 2.0 },
	];

	return (
		<AbsoluteFill
			style={{ opacity, backgroundColor: '#020617' }}
			className="flex flex-col items-center justify-center px-16"
		>
			<div
				style={{
					opacity: title.opacity,
					transform: `translateY(${title.translateY}px)`,
				}}
				className="text-5xl font-bold text-emerald-400 mb-10"
			>
				Meet fastbrowser
			</div>
			<div className="bg-slate-900 rounded-2xl p-8 w-full max-w-4xl border border-slate-700">
				{cmds.map((cmd, i) => {
					const a = animateIn(frame, cmd.delay, fps);
					return (
						<div
							key={i}
							style={{
								opacity: a.opacity,
								transform: `translateY(${a.translateY}px)`,
							}}
							className="font-mono text-lg text-green-300 mb-3"
						>
							{cmd.text}
						</div>
					);
				})}
			</div>
			<div
				style={{
					opacity: animateIn(frame, 2.5, fps).opacity,
				}}
				className="text-2xl text-slate-400 mt-8"
			>
				Control Chrome from your terminal
			</div>
		</AbsoluteFill>
	);
};

/* ── Scene 3: The Secret Sauce ───────────────────────── */
const Scene3: React.FC = () => {
	const frame = useCurrentFrame();
	const { fps, durationInFrames } = useVideoConfig();
	const opacity = fadeInOut(frame, durationInFrames, FADE_FRAMES);
	const title = animateIn(frame, 0, fps);
	const tree = animateIn(frame, 0.6, fps);
	const label = animateIn(frame, 1.2, fps);

	const treeLines = [
		'WebArea "My Page"',
		'  navigation',
		'    link "Home"',
		'    link "About"',
		'  main',
		'    heading "Welcome"',
		'    button "Sign Up"',
	];

	return (
		<AbsoluteFill
			style={{ opacity, backgroundColor: '#0f172a' }}
			className="flex flex-col items-center justify-center px-16"
		>
			<div
				style={{
					opacity: title.opacity,
					transform: `translateY(${title.translateY}px)`,
				}}
				className="text-5xl font-bold text-amber-400 mb-8"
			>
				The Secret Sauce: a11y_parse
			</div>
			<div
				style={{
					opacity: tree.opacity,
					transform: `translateY(${tree.translateY}px)`,
				}}
				className="bg-slate-800 rounded-2xl p-8 w-full max-w-3xl border border-slate-700"
			>
				{treeLines.map((line, i) => (
					<div key={i} className="font-mono text-xl text-cyan-300 leading-relaxed whitespace-pre">
						{line}
					</div>
				))}
			</div>
			<div
				style={{
					opacity: label.opacity,
					transform: `translateY(${label.translateY}px)`,
				}}
				className="text-2xl text-slate-400 mt-6"
			>
				The accessibility tree: clean, semantic, structured
			</div>
		</AbsoluteFill>
	);
};

/* ── Scene 4: CSS-like Selectors ─────────────────────── */
const Scene4: React.FC = () => {
	const frame = useCurrentFrame();
	const { fps, durationInFrames } = useVideoConfig();
	const opacity = fadeInOut(frame, durationInFrames, FADE_FRAMES);
	const title = animateIn(frame, 0, fps);

	const selectors = [
		{ sel: 'link', desc: 'All links', delay: 0.5 },
		{ sel: 'button[name="Submit"]', desc: 'Button by name', delay: 1.0 },
		{ sel: 'navigation > link', desc: 'Nav links only', delay: 1.5 },
		{ sel: 'link[href^="https"]', desc: 'HTTPS links', delay: 2.0 },
	];

	return (
		<AbsoluteFill
			style={{ opacity, backgroundColor: '#020617' }}
			className="flex flex-col items-center justify-center px-16"
		>
			<div
				style={{
					opacity: title.opacity,
					transform: `translateY(${title.translateY}px)`,
				}}
				className="text-5xl font-bold text-violet-400 mb-10"
			>
				CSS-like Selectors
			</div>
			<div className="grid grid-cols-2 gap-6 w-full max-w-4xl">
				{selectors.map((s, i) => {
					const a = animateIn(frame, s.delay, fps);
					return (
						<div
							key={i}
							style={{
								opacity: a.opacity,
								transform: `translateY(${a.translateY}px)`,
							}}
							className="bg-slate-800 rounded-xl p-6 border border-slate-700"
						>
							<div className="font-mono text-xl text-emerald-300 mb-2">
								{s.sel}
							</div>
							<div className="text-lg text-slate-400">{s.desc}</div>
						</div>
					);
				})}
			</div>
		</AbsoluteFill>
	);
};

/* ── Scene 5: AI-Friendly ────────────────────────────── */
const Scene5: React.FC = () => {
	const frame = useCurrentFrame();
	const { fps, durationInFrames } = useVideoConfig();
	const opacity = fadeInOut(frame, durationInFrames, FADE_FRAMES);
	const title = animateIn(frame, 0, fps);

	const stats = [
		{ label: 'DOM tokens', value: '~50,000', color: 'text-red-400', delay: 0.5 },
		{ label: 'A11y tree tokens', value: '~1,000', color: 'text-emerald-400', delay: 1.0 },
		{ label: 'Reduction', value: '10-50x smaller', color: 'text-amber-400', delay: 1.5 },
	];

	return (
		<AbsoluteFill
			style={{ opacity, backgroundColor: '#0f172a' }}
			className="flex flex-col items-center justify-center px-16"
		>
			<div
				style={{
					opacity: title.opacity,
					transform: `translateY(${title.translateY}px)`,
				}}
				className="text-5xl font-bold text-sky-400 mb-12"
			>
				Built for AI Agents
			</div>
			<div className="flex gap-8">
				{stats.map((s, i) => {
					const a = animateIn(frame, s.delay, fps);
					return (
						<div
							key={i}
							style={{
								opacity: a.opacity,
								transform: `translateY(${a.translateY}px)`,
							}}
							className="bg-slate-800 rounded-2xl p-8 flex flex-col items-center border border-slate-700 min-w-[220px]"
						>
							<div className={`text-4xl font-bold ${s.color} mb-3`}>
								{s.value}
							</div>
							<div className="text-xl text-slate-400">{s.label}</div>
						</div>
					);
				})}
			</div>
		</AbsoluteFill>
	);
};

/* ── Scene 6: Workflow ───────────────────────────────── */
const Scene6: React.FC = () => {
	const frame = useCurrentFrame();
	const { fps, durationInFrames } = useVideoConfig();
	const opacity = fadeInOut(frame, durationInFrames, FADE_FRAMES);
	const title = animateIn(frame, 0, fps);

	const steps = [
		{ icon: '1', text: 'Navigate to page', delay: 0.4 },
		{ icon: '2', text: 'Take a11y snapshot', delay: 0.8 },
		{ icon: '3', text: 'Query elements', delay: 1.2 },
		{ icon: '4', text: 'Click / Fill / Interact', delay: 1.6 },
		{ icon: '5', text: 'Repeat', delay: 2.0 },
	];

	return (
		<AbsoluteFill
			style={{ opacity, backgroundColor: '#020617' }}
			className="flex flex-col items-center justify-center px-16"
		>
			<div
				style={{
					opacity: title.opacity,
					transform: `translateY(${title.translateY}px)`,
				}}
				className="text-5xl font-bold text-rose-400 mb-10"
			>
				The AI Workflow
			</div>
			<div className="flex items-center gap-4">
				{steps.map((step, i) => {
					const a = animateIn(frame, step.delay, fps);
					return (
						<div key={i} className="flex items-center gap-4">
							<div
								style={{
									opacity: a.opacity,
									transform: `translateY(${a.translateY}px)`,
								}}
								className="bg-slate-800 rounded-xl px-6 py-5 flex flex-col items-center border border-slate-700"
							>
								<div className="text-3xl font-bold text-white mb-2">{step.icon}</div>
								<div className="text-base text-slate-300 text-center whitespace-nowrap">{step.text}</div>
							</div>
							{i < steps.length - 1 && (
								<div
									style={{ opacity: a.opacity }}
									className="text-3xl text-slate-500"
								>
									{'\u2192'}
								</div>
							)}
						</div>
					);
				})}
			</div>
		</AbsoluteFill>
	);
};

/* ── Scene 7: Outro ──────────────────────────────────── */
const Scene7: React.FC = () => {
	const frame = useCurrentFrame();
	const { fps, durationInFrames } = useVideoConfig();
	const opacity = fadeInOut(frame, durationInFrames, FADE_FRAMES);
	const title = animateIn(frame, 0, fps);
	const cmd = animateIn(frame, 0.5, fps);
	const tag = animateIn(frame, 1.0, fps);

	return (
		<AbsoluteFill
			style={{ opacity, backgroundColor: '#0f172a' }}
			className="flex flex-col items-center justify-center px-16"
		>
			<div
				style={{
					opacity: title.opacity,
					transform: `translateY(${title.translateY}px)`,
				}}
				className="text-5xl font-bold text-white mb-8"
			>
				Try it today
			</div>
			<div
				style={{
					opacity: cmd.opacity,
					transform: `translateY(${cmd.translateY}px)`,
				}}
				className="bg-slate-800 rounded-xl px-10 py-5 font-mono text-2xl text-emerald-400 border border-slate-700 mb-8"
			>
				npm install -g fastbrowser_cli
			</div>
			<div
				style={{
					opacity: tag.opacity,
					transform: `translateY(${tag.translateY}px)`,
				}}
				className="text-3xl text-slate-400"
			>
				Open source on npm &bull; Clean, fast, semantic
			</div>
		</AbsoluteFill>
	);
};

/* ── Main Composition ────────────────────────────────── */
export const MyComposition: React.FC = () => {
	const scenes = [
		{ Component: Scene1, duration: SCENE1_FRAMES },
		{ Component: Scene2, duration: SCENE2_FRAMES },
		{ Component: Scene3, duration: SCENE3_FRAMES },
		{ Component: Scene4, duration: SCENE4_FRAMES },
		{ Component: Scene5, duration: SCENE5_FRAMES },
		{ Component: Scene6, duration: SCENE6_FRAMES },
		{ Component: Scene7, duration: SCENE7_FRAMES },
	];

	let offset = 0;
	return (
		<AbsoluteFill style={{ backgroundColor: '#0f172a' }}>
			{scenes.map((scene, i) => {
				const from = offset;
				offset += scene.duration;
				return (
					<Sequence
						key={i}
						from={from}
						durationInFrames={scene.duration}
						premountFor={30}
					>
						<scene.Component />
						<Audio src={staticFile(`scenes/scene${i + 1}.mp3`)} />
					</Sequence>
				);
			})}
		</AbsoluteFill>
	);
};

