import {
	useCurrentFrame,
	useVideoConfig,
	interpolate,
	Easing,
	Sequence,
	staticFile,
	AbsoluteFill,
} from 'remotion';
import { Audio } from '@remotion/media';

const SCENE1_FRAMES = 412;
const SCENE2_FRAMES = 543;
const SCENE3_FRAMES = 520;
const SCENE4_FRAMES = 514;
const SCENE5_FRAMES = 454;
const SCENE6_FRAMES = 482;
const SCENE7_FRAMES = 286;

const FADE_FRAMES = 18;

const fadeInOut = (frame: number, durationInFrames: number, fadeFrames: number) => {
	const fadeIn = interpolate(frame, [0, fadeFrames], [0, 1], {
		extrapolateLeft: 'clamp',
		extrapolateRight: 'clamp',
		easing: Easing.bezier(0.16, 1, 0.3, 1),
	});
	const fadeOut = interpolate(
		frame,
		[durationInFrames - fadeFrames, durationInFrames],
		[1, 0],
		{
			extrapolateLeft: 'clamp',
			extrapolateRight: 'clamp',
			easing: Easing.bezier(0.45, 0, 0.55, 1),
		},
	);
	return fadeIn * fadeOut;
};

const animateIn = (frame: number, delay: number, fps: number) => {
	const startFrame = delay * fps;
	return {
		opacity: interpolate(frame, [startFrame, startFrame + 15], [0, 1], {
			extrapolateLeft: 'clamp',
			extrapolateRight: 'clamp',
			easing: Easing.bezier(0.16, 1, 0.3, 1),
		}),
		translateY: interpolate(frame, [startFrame, startFrame + 15], [30, 0], {
			extrapolateLeft: 'clamp',
			extrapolateRight: 'clamp',
			easing: Easing.bezier(0.16, 1, 0.3, 1),
		}),
	};
};

