				style={{
					opacity: cmd.opacity,
					transform: `translateY(${cmd.translateY}px)`,
				}}
				className="bg-slate-800 rounded-xl px-10 py-5 font-mono text-2xl text-emerald-400 border border-slate-700 mb-8"
			>
				npm install -g fastbrowser_cli
			</div>
			<div
				style={{
					opacity: tag.opacity,
					transform: `translateY(${tag.translateY}px)`,
				}}
				className="text-3xl text-slate-400"
			>
				Open source on npm &bull; Clean, fast, semantic
			</div>
		</AbsoluteFill>
	);
};

/* ── Main Composition ────────────────────────────────── */
export const MyComposition: React.FC = () => {
	const scenes = [
		{ Component: Scene1, duration: SCENE1_FRAMES },
		{ Component: Scene2, duration: SCENE2_FRAMES },
		{ Component: Scene3, duration: SCENE3_FRAMES },
		{ Component: Scene4, duration: SCENE4_FRAMES },
		{ Component: Scene5, duration: SCENE5_FRAMES },
		{ Component: Scene6, duration: SCENE6_FRAMES },
		{ Component: Scene7, duration: SCENE7_FRAMES },
	];

	let offset = 0;
	return (
		<AbsoluteFill style={{ backgroundColor: '#0f172a' }}>
			{scenes.map((scene, i) => {
				const from = offset;
				offset += scene.duration;
				return (
					<Sequence
						key={i}
						from={from}
						durationInFrames={scene.duration}
						premountFor={30}
					>
						<scene.Component />
						<Audio src={staticFile(`scenes/scene${i + 1}.mp3`)} />
					</Sequence>
				);
			})}
		</AbsoluteFill>
	);
};

